184: 		os.CentOS:             {},
185: 		os.Rocky:              {},
186: 		os.Alma:               {},
187: 		os.Fedora:             {},
188: 		os.Amazon:             {},
189: 		os.Oracle:             {},
190: 		os.Windows:            {},
191: 		os.OpenSUSE:           {},
192: 		os.OpenSUSELeap:       {},
193: 		os.OpenSUSETumbleweed: {},
194: 		os.SLES:               {},
195: 		os.Photon:             {},
196: 		os.Alpine:             {},
197: 	}
