114: func getCveContents(cveID string, vul trivyDBTypes.Vulnerability) (contents map[CveContentType][]CveContent) {
115: 	contents = map[CveContentType][]CveContent{}
116: 	refs := []Reference{}
117: 	for _, refURL := range vul.References {
118: 		refs = append(refs, Reference{Source: "trivy", Link: refURL})
119: 	}
120: 
121: 	contents[Trivy] = []CveContent{
122: 		{
123: 			Type:          Trivy,
124: 			CveID:         cveID,
125: 			Title:         vul.Title,
126: 			Summary:       vul.Description,
127: 			Cvss3Severity: string(vul.Severity),
128: 			References:    refs,
129: 		},
130: 	}
131: 	return contents
132: }
