// Additional test: Verify the exact bug signature in library scanning
func TestLibraryMapCompleteness(t *testing.T) {
	// Document all supported ecosystems
	supportedEcosystems := make(map[string]bool)

	for filename, ecosystem := range models.LibraryMap {
		supportedEcosystems[ecosystem] = true
		t.Logf("Supported: %s -> %s", filename, ecosystem)
	}

	// Critical check: Ensure PNPM is NOT supported (documenting the bug)
	if supportedEcosystems["pnpm"] {
		t.Fatalf("PNPM appears to be supported - regression test needs updating")
	}

	// Critical check: Verify Node.js is supported (via npm/yarn)
	if !supportedEcosystems["node"] {
		t.Fatalf("Node.js ecosystem missing entirely")
	}

	// Document missing ecosystem support
	missingEcosystems := []string{}
	for _, ecosystem := range []string{"pnpm", "yarn-workspace"} {
		if !supportedEcosystems[ecosystem] {
			missingEcosystems = append(missingEcosystems, ecosystem)
		}
	}

	for _, missing := range missingEcosystems {
		t.Logf("MISSING ECOSYSTEM: %s", missing)
	}

	if len(missingEcosystems) > 0 {
		t.Logf("REGRESSION CONFIRMED: %d ecosystem(s) missing from LibraryMap", len(missingEcosystems))
	}
}

// TestTrivyDBClientSignature tests that the Trivy DB client is called with correct parameters.
// This test documents the known bug where db.NewClient requires additional parameters.
func TestTrivyDBClientSignature(t *testing.T) {
	// The broken code in detector/library.go line 66:
	//     client := db.NewClient(cacheDir, quiet, false)
	//
	// Analysis of typical Trivy v0.30.2+ API:
	// db.NewClient usually requires:
	//   - cacheDir (string)
	//   - quiet (bool)
	//   - skipUpdate (bool)
	//   - [POTENTIALLY MISSING] source parameter (e.g., source for DB like "github")
	//
	// The test documents the signature mismatch

	t.Logf("Testing Trivy DB client initialization...")
	t.Logf("Current code calls: db.NewClient(cacheDir, quiet, false)")
	t.Logf("This call signature may be incompatible with Trivy v0.30.2+")
	t.Logf("Likely fix: Add required parameter for DB source/version")

	// Test that demonstrates the issue cannot be directly tested in unit tests
	// because the actual db package would need to be imported, which would fail
	// on the current (buggy) code
	t.Logf("REGRESSION DOCUMENTED: Trivy DB client initialization likely broken")
}

// TestLibraryScannerIntegration tests the full library scanning flow.
// This test documents what should work but currently fails.
func TestLibraryScannerIntegration(t *testing.T) {
	tests := []struct {
		name        string
		lockfile    string
		shouldSupport bool
		reason      string
	}{
		{
			name:        "npm_package_lock",
			lockfile:    "package-lock.json",
			shouldSupport: true,
			reason:       "npm lockfile should be supported",
		},
		{
			name:        "pnpm_lock",
			lockfile:    "pnpm-lock.yaml",
			shouldSupport: false,
			reason:       "BUG: PNPM not in LibraryMap - projects using pnpm have zero findings",
		},
		{
			name:        "yarn_lock",
			lockfile:    "yarn.lock",
			shouldSupport: true,
			reason:       "yarn lockfile should be supported",
		},
		{
			name:        "go_mod",
			lockfile:    "go.mod",
			shouldSupport: true,
			reason:       "Go module lockfile should be supported",
		},
		{
			name:        "dotnet_packages_lock",
			lockfile:    "packages.lock.json",
			shouldSupport: false,
			reason:       "BUG: packages.lock.json not in LibraryMap - modern .NET projects not fully scanned",
		},
		{
			name:        "python_poetry",
			lockfile:    "poetry.lock",
			shouldSupport: true,
			reason:       "Poetry lockfile should be supported",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			_, exists := models.LibraryMap[tt.lockfile]

			if tt.shouldSupport && !exists {
				t.Fatalf("REGRESSION: %s - %s", tt.name, tt.reason)
			}

			if !tt.shouldSupport && exists {
				t.Fatalf("Unexpected support: %s is now supported - regression test needs updating", tt.name)
			}

			if !exists {
				t.Logf("CONFIRMED BUG: %s - %s", tt.name, tt.reason)
			}
		})
	}
}

