	// non-library analyzers during library scanning

	// Create a minimal test scenario similar to scanner/base.go AnalyzeLibraries()
	ctx := context.Background()

	// Recreate the disabled analyzers list from scanner/base.go:669-728
	disabledAnalyzers := []analyzer.Type{
		// OS analyzers
		analyzer.TypeOSRelease,
		analyzer.TypeAlpine,
		analyzer.TypeAmazon,
		analyzer.TypeCBLMariner,
		analyzer.TypeDebian,
		analyzer.TypePhoton,
		analyzer.TypeCentOS,
		analyzer.TypeRocky,
		analyzer.TypeAlma,
		analyzer.TypeFedora,
		analyzer.TypeOracle,
		analyzer.TypeRedHatBase,
		analyzer.TypeSUSE,
		analyzer.TypeUbuntu,

		// OS Package analyzers
		analyzer.TypeApk,
		analyzer.TypeDpkg,
		analyzer.TypeDpkgLicense,
		analyzer.TypeRpm,
		analyzer.TypeRpmqa,

		// OS Package Repository
		analyzer.TypeApkRepo,

		// Image Config
		analyzer.TypeApkCommand,

		// Structured Config
		analyzer.TypeYaml,
		analyzer.TypeJSON,
		analyzer.TypeDockerfile,
		analyzer.TypeTerraform,
		analyzer.TypeCloudFormation,
		analyzer.TypeHelm,

		// License
		analyzer.TypeLicenseFile,

		// Secrets
		analyzer.TypeSecret,

		// Red Hat
		analyzer.TypeRedHatContentManifestType,
		analyzer.TypeRedHatDockerfileType,
	}

	// Create analyzer group with disabled analyzers
	analGroup := analyzer.NewAnalyzerGroup(analyzer.GroupBuiltin, disabledAnalyzers)

	if analGroup == nil {
		t.Fatalf("Failed to create analyzer group - indicates potential API change")
	}

	// Verify that we can perform analysis without the OS analyzers
	testContent := `{"name": "test", "version": "1.0.0"}`

	ctx, cancel := context.WithCancel(ctx)
	defer cancel()

	// Attempt to analyze the file
	var wg sync.WaitGroup
	result := new(analyzer.AnalysisResult)

	err := analGroup.AnalyzeFile(
		ctx,
		&wg,
		semaphore.NewWeighted(1),
		result,
		"",
		"package.json",
		&DummyFileInfo{size: int64(len(testContent)), filemode: 0644},
		func() (io.ReadSeekCloserAt, error) {
			return io.NopCloser(bytes.NewReader([]byte(testContent))), nil
		},
		nil,
		analyzer.AnalysisOptions{Offline: false},
	)

	wg.Wait()

	if err != nil {
		t.Logf("Analyzer execution: %v", err)
	}

	t.Logf("Analyzer scope control configured with %d disabled analyzer types", len(disabledAnalyzers))
}

